export async function deployContract(abi: any, bytecode: string, args: any[]) {
	if (!window.ethereum) throw new Error("No crypto wallet found");

	const accounts = (await window.ethereum.request({
		method: "eth_requestAccounts",
	})) as string[];

	if (accounts.length === 0) throw new Error("No accounts found");

	if (!bytecode || bytecode === "0x") {
		throw new Error("Contract bytecode is missing. Please provide the compiled contract bytecode in lib/contract.ts.");
	}

	// In a real dApp with ethers/viem, we'd encode parameters.
	// Here we assume the user might provide a pre-encoded or simple bytecode.
	const txHash = (await window.ethereum.request({
		method: "eth_sendTransaction",
		params: [{
			from: accounts[0],
			data: bytecode,
		}],
	})) as string;

	return txHash;
}

